def lastSubstring(s):
    i, j, k = 0, 1, 0
    n = len(s)
    while j + k < n:
        if s[i+k] == s[j+k]: k += 1
        elif s[i+k] < s[j+k]:
            i = max(i + k + 1, j)
            j, k = i + 1, 0
        else:
            j, k = j + k + 1, 0
    return s[i:]

